const fs=require("fs"),path=require("path"),[,,action,targetPath]=process.argv;if("read"===action||"readfile"===action)try{const e=fs.readFileSync(targetPath,"utf8");process.stdout.write(e),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else if("write"===action){let e="";process.stdin.setEncoding("utf8"),process.stdin.on("data",t=>{e+=t}),process.stdin.on("end",()=>{try{fs.writeFileSync(targetPath,e,"utf8"),process.stdout.write("ok"),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}}),process.stdin.resume()}else if("readdir"===action)try{const e=fs.readdirSync(targetPath);process.stdout.write(JSON.stringify(e)),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else if("exists"===action)try{const e=fs.existsSync(targetPath);process.stdout.write(e?"true":"false"),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else if("readxml"===action)try{const e=fs.readFileSync(targetPath,"utf8"),t=/<Guid>([^<]+)<\/Guid>/i.exec(e),s=/<Name>([^<]+)<\/Name>/i.exec(e),r=/<FileNamePostPart>([^<]+)<\/FileNamePostPart>/i.exec(e);process.stdout.write(JSON.stringify({guid:t?t[1].trim():"",name:s?s[1].trim():"",fileNamePostPart:r?r[1].trim():""})),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else if("scanprojects"===action)try{const e=fs.readdirSync(targetPath),t=[];e.forEach(e=>{const s=path.join(targetPath,e,"Settings.xml");try{if(!fs.existsSync(s))return;const r=fs.readFileSync(s,"utf8"),i=/<Guid>([^<]+)<\/Guid>/i.exec(r),c=/<Name>([^<]+)<\/Name>/i.exec(r),a=/<FileNamePostPart>([^<]+)<\/FileNamePostPart>/i.exec(r);t.push({dir:path.join(targetPath,e),guid:i?i[1].trim():"",name:c?c[1].trim():"",fileNamePostPart:a?a[1].trim():""})}catch(e){}}),process.stdout.write(JSON.stringify(t)),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else if("open"===action){const{exec:e}=require("child_process");try{e(`start "" "${targetPath.replace(/"/g,'\\"')}"`,e=>{e?(process.stderr.write(e.message),process.exit(1)):(process.stdout.write("ok"),process.exit(0))})}catch(e){process.stderr.write(e.message),process.exit(1)}}else if("mkdir"===action)try{fs.mkdirSync(targetPath,{recursive:!0}),process.stdout.write("ok"),process.exit(0)}catch(e){process.stderr.write(e.message),process.exit(1)}else process.stderr.write("Unknown action: "+action),process.exit(1);